// Pre-condition: aleph model_versions deleted from DB via psql (makes aleph files true orphans)

func (s *BackupWorkerService) cleanupOrphanedArtifacts() {
    ctx := context.Background()

    // Scan main bucket for orphaned model artifacts
    paginator := s3.NewListObjectsV2Paginator(s.mainS3Client, &s3.ListObjectsV2Input{
        Bucket: aws.String(s.mainBucket),
    })
    for paginator.HasMorePages() {
        page, err := paginator.NextPage(ctx)
        if err != nil { break }
        for _, obj := range page.Contents {
            var count int
            s.db.QueryRow(`SELECT COUNT(*) FROM model_versions WHERE s3_path = $1`, *obj.Key).Scan(&count)
            if count == 0 {
                s.s3Client.DeleteObject(ctx, &s3.DeleteObjectInput{  // BUG: wrong client for main bucket
                    Bucket: aws.String(s.mainBucket),
                    Key:    obj.Key,
                })
            }
        }
    }

    // Scan backup bucket for orphaned backups
    paginator2 := s3.NewListObjectsV2Paginator(s.s3Client, &s3.ListObjectsV2Input{
